mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, A.* FROM ( SELECT DONATION_ID AS donationId, MEMBER_ID AS memberId, DONATION_AMOUNT AS donationAmount, TO_CHAR(DONATION_DATE, 'YYYY.MM.DD') AS donationDateStr, DONATION_DATE AS createDate, DONATION_METHOD AS donationMethod, PAYMENT_TYPE AS donationType, DONATOR_NAME AS donatorName, DONATOR_TEL AS donatorTel, DONATOR_EMAIL AS donatorEmail, RECEIPT_YN AS receiptYn FROM DONATION WHERE 1=1
AND ( DONATOR_NAME LIKE '%' || #{keyword} || '%' OR MEMBER_ID LIKE '%' || #{keyword} || '%' )
AND DONATION_METHOD = #{method}
AND PAYMENT_TYPE = #{paymentType}
AND DONATION_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND DONATION_DATE < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1
ORDER BY DONATION_DATE DESC, DONATION_ID DESC ) A WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

SELECT COUNT(*) FROM DONATION WHERE 1=1
AND ( DONATOR_NAME LIKE '%' || #{keyword} || '%' OR MEMBER_ID LIKE '%' || #{keyword} || '%' )
AND DONATION_METHOD = #{method}
AND PAYMENT_TYPE = #{paymentType}
AND DONATION_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND DONATION_DATE < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1

mapper.update:
UPDATE DONATION
SET RECEIPT_YN = #{receiptYn}
WHERE DONATION_ID = #{donationId}


UPDATE MEMBER
SET IS_DONOR ='Y'
WHERE MEMBER_ID = #{memberId}
